DESIGN RULES: Use ONLY inline CSS. Dark executive color scheme: deep navy (#0f3460), electric blue (#1e90ff), clean white. Max-width 680px centered. Card-based layout. Return ONLY raw HTML starting with <!DOCTYPE html>.`;

return [{json: {prompt}}];

const raw = $input.first().json.candidates[0].content.parts[0].text;
const html = raw.replace(/^```html\n?/i, '').replace(/^```\n?/i, '').replace(/\n?```$/i, '').trim();
const compiled = $('Compile Briefing Data').first().json;
const day = new Date().toLocaleDateString('en-GB', {weekday:'long', day:'numeric', month:'long'});
return [{ json: {
  subject: `???? Chief of Staff Briefing - ${day} | ${compiled.activeCount} active, ${compiled.unreadEmails} unread`,
  body: html
}}];

const executions = ($input.first().json.data || []);
const windowMs = 20 * 60 * 1000;
const cutoff = Date.now() - windowMs;

const recent = executions.filter(e => new Date(e.startedAt).getTime() > cutoff);

const byWorkflow = {};
recent.forEach(e => {
  if (!e.workflowId) return;
  if (!byWorkflow[e.workflowId]) byWorkflow[e.workflowId] = {workflowId: e.workflowId, count: 0};
  byWorkflow[e.workflowId].count++;
});

const failures = Object.values(byWorkflow);
const critical = failures.filter(f => f.count >= 2);
const failingIds = failures.map(f => f.workflowId).filter(Boolean);

return [{ json: {
  failureCount: failures.length,
  criticalCount: critical.length,
  failingIds,
  criticalWorkflows: critical.map(f => `WorkflowID ${f.workflowId} (${f.count} errors)`).join(', ') || 'None',
  allFailures: failures.map(f => `${f.workflowId}: ${f.count}`).join(', '),
  timestamp: new Date().toISOString(),
  windowMinutes: 20
}}];

const h = $input.first().json;
const prompt = `URGENT: System alert for the Super-Agent n8n automation platform.

In the last ${h.windowMinutes} minutes:
- Failing workflows: ${h.failureCount}
- Critical (2+ errors): ${h.criticalWorkflows}
- All failures: ${h.allFailures}
- Failing workflow IDs: ${h.failingIds.join(', ')}

Provide:
1. A concise 2-sentence diagnosis
2. Immediate recommended action (1 sentence)
3. Severity level: LOW / MEDIUM / HIGH / CRITICAL
4. Whether auto-restart is appropriate (yes/no)

Return JSON: {"diagnosis": "...", "action": "...", "severity": "...", "auto_restart": true/false, "subject_line": "alert email subject max 60 chars"}`;
return [{json: {prompt, failureCount: h.failureCount, criticalWorkflows: h.criticalWorkflows, failingIds: h.failingIds}}];

